import argparse
import json
import logging
import signal
import socket
import sys
import threading
import time
from typing import Dict, List, Tuple, Any

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
)

DEFAULT_HOST = "0.0.0.0"
DEFAULT_PORT = 27015
MAX_PACKET_SIZE = 65507


class GameState:
    def __init__(self) -> None:
        self._lock = threading.Lock()
        self.server_name = "Example Game Server"
        self.map_name = "arena_01"
        self.game_mode = "deathmatch"
        self.max_players = 64
        self.version = "1.0.0"
        self.start_time = time.time()
        self.players: List[Dict[str, Any]] = [
            {"name": "Alice", "score": 12, "ping": 34, "team": "red"},
            {"name": "Bob", "score": 8, "ping": 52, "team": "blue"},
            {"name": "Carol", "score": 15, "ping": 28, "team": "red"},
        ]

    def snapshot(self) -> Dict[str, Any]:
        with self._lock:
            return {
                "server_name": self.server_name,
                "map": self.map_name,
                "mode": self.game_mode,
                "version": self.version,
                "uptime_seconds": int(time.time() - self.start_time),
                "players_online": len(self.players),
                "max_players": self.max_players,
                "players": list(self.players),
                "state": {
                    "round": 3,
                    "time_remaining": 412,
                    "teams": {
                        "red": {
                            "score": 24,
                            "players": sum(1 for p in self.players if p.get("team") == "red"),
                        },
                        "blue": {
                            "score": 21,
                            "players": sum(1 for p in self.players if p.get("team") == "blue"),
                        },
                    },
                },
            }


class UDPGameServer:
    def __init__(self, host: str, port: int, game_state: GameState) -> None:
        self.host = host
        self.port = port
        self.game_state = game_state
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.running = False

    def start(self) -> None:
        self.sock.bind((self.host, self.port))
        self.running = True
        logging.info("UDP game server listening on %s:%d", self.host, self.port)
        while self.running:
            try:
                data, addr = self.sock.recvfrom(8192)
            except OSError:
                break
            except Exception as e:
                logging.exception("recvfrom error: %s", e)
                continue

            try:
                self.handle_packet(data, addr)
            except Exception as e:
                logging.exception("Error handling packet from %s: %s", addr, e)

    def stop(self) -> None:
        self.running = False
        try:
            self.sock.close()
        except Exception:
            pass

    def handle_packet(self, data: bytes, addr: Tuple[str, int]) -> None:
        message = data.decode("utf-8", errors="ignore").strip()
        logging.info("Received query from %s:%d: %r", addr[0], addr[1], message)

        if message.upper() in {"STATUS", "GETSTATUS", "INFO"}:
            payload = self.build_status_response()
            self.send_response(payload, addr)
        elif message.upper() == "PING":
            self.send_response(b'{"type":"pong"}', addr)
        else:
            self.send_response(b'{"error":"unknown_query"}', addr)

    def build_status_response(self) -> bytes:
        response = {
            "type": "status",
            "timestamp": int(time.time()),
            "data": self.game_state.snapshot(),
        }
        encoded = json.dumps(response, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
        if len(encoded) > MAX_PACKET_SIZE:
            encoded = json.dumps(
                {"error": "response_too_large", "size": len(encoded)},
                separators=(",", ":"),
            ).encode("utf-8")
        return encoded

    def send_response(self, payload: bytes, addr: Tuple[str, int]) -> None:
        sent = self.sock.sendto(payload, addr)
        logging.info("Sent %d bytes to %s:%d", sent, addr[0], addr[1])


def main() -> None:
    parser = argparse.ArgumentParser(description="UDP game query server")
    parser.add_argument("--host", default=DEFAULT_HOST)
    parser.add_argument("--port", type=int, default=DEFAULT_PORT)
    args = parser.parse_args()

    state = GameState()
    server = UDPGameServer(args.host, args.port, state)

    def shutdown_handler(signum, frame):
        logging.info("Shutting down on signal %s", signum)
        server.stop()
        sys.exit(0)

    signal.signal(signal.SIGINT, shutdown_handler)
    signal.signal(signal.SIGTERM, shutdown_handler)

    server.start()


if __name__ == "__main__":
    main()